mapper.insert:
INSERT INTO RawSource (
    workspace_id, source_uri, title, content_hash, source_type, status, created_at, updated_at
) VALUES (
    #{workspaceId}, #{sourceUri}, #{title}, #{contentHash}, #{sourceType}, #{status}, GETUTCDATE(), GETUTCDATE()
)

mapper.select:
SELECT *
FROM RawSource
WHERE workspace_id = #{workspaceId} AND source_uri = #{sourceUri}
